def histogram(test):
    """The function accepts a space-separated string of lowercase letters and returns a dictionary where keys are the letters with the highest frequency, and values are their counts. If multiple letters share the same maximum frequency, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    if not test:
        return {}

    letters = test.split()
    counts = {}
    for letter in letters:
        counts[letter] = counts.get(letter, 0) + 1

    max_count = max(counts.values())
    result = {letter: count for letter, count in counts.items() if count == max_count}
    return result
